+            &sqlite_path,
+            &config.storage_root,
+        )
+    } else {
+        mcp_agent_mail_db::ensure_sqlite_file_healthy(&sqlite_path)
+    };
+
+    match recovery {
+        Ok(()) => {
+            tracing::warn!(
+                sqlite = %sqlite_path.display(),
+                "[startup-search] sqlite auto-recovery succeeded; retrying backfill once"
