+        TUI_SPIN_WATCHDOG_STARTUP_SECS_DEFAULT,
+    )
+    .max(window_secs);
+    let cpu_threshold_pct = env_u64_or_default(
+        "AM_TUI_SPIN_WATCHDOG_CPU_PCT",
